package com.hr.service;

import com.hr.model.*;
import com.hr.security.AuthenticationHandler;

import javax.jws.HandlerChain;
import javax.jws.WebService;
import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.format.DateTimeParseException;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Level;
import java.util.logging.Logger;

@WebService(
    serviceName = "EmployeeManagementService",
    portName = "EmployeeManagementPort",
    endpointInterface = "com.hr.service.EmployeeManagementService",
    targetNamespace = "http://service.hr.com/employee",
    wsdlLocation = "WEB-INF/wsdl/EmployeeManagementService.wsdl"
)
@HandlerChain(file = "handler-chain.xml")
public class EmployeeManagementServiceImpl implements EmployeeManagementService {

    private static final Logger LOGGER = Logger.getLogger(EmployeeManagementServiceImpl.class.getName());
    private static final DateTimeFormatter DATE_FORMATTER = DateTimeFormatter.ISO_LOCAL_DATE;

    // In-memory store for demonstration; replace with database in production
    private final Map<String, Employee> employeeStore = new ConcurrentHashMap<>();

    public EmployeeManagementServiceImpl() {
        // Seed sample data
        seedSampleData();
    }

    private void seedSampleData() {
        Employee emp1 = new Employee("EMP001", "John", "Doe", "Engineering",
                "Senior Developer", new BigDecimal("95000.00"), LocalDate.of(2019, 3, 15));
        Employee emp2 = new Employee("EMP002", "Jane", "Smith", "Marketing",
                "Marketing Manager", new BigDecimal("85000.00"), LocalDate.of(2020, 7, 1));
        Employee emp3 = new Employee("EMP003", "Bob", "Johnson", "Finance",
                "Financial Analyst", new BigDecimal("75000.00"), LocalDate.of(2021, 1, 10));
        employeeStore.put(emp1.getEmployeeId(), emp1);
        employeeStore.put(emp2.getEmployeeId(), emp2);
        employeeStore.put(emp3.getEmployeeId(), emp3);
    }

    @Override
    public ServiceResponse updateSalary(SalaryUpdateRequest request) {
        LOGGER.info("Processing salary update for employee: " + sanitizeLogInput(request.getEmployeeId()));

        // Validate request
        if (request == null || request.getEmployeeId() == null || request.getEmployeeId().trim().isEmpty()) {
            return new ServiceResponse(false, "Employee ID is required", "INVALID_REQUEST");
        }

        if (request.getNewSalary() == null || request.getNewSalary().compareTo(BigDecimal.ZERO) <= 0) {
            return new ServiceResponse(false, "New salary must be a positive value", "INVALID_SALARY");
        }

        if (request.getApprovedBy() == null || request.getApprovedBy().trim().isEmpty()) {
            return new ServiceResponse(false, "Approver is required for salary updates", "MISSING_APPROVER");
        }

        String employeeId = request.getEmployeeId().trim();
        Employee employee = employeeStore.get(employeeId);

        if (employee == null) {
            return new ServiceResponse(false, "Employee not found", "EMPLOYEE_NOT_FOUND");
        }

        if (!employee.isActive()) {
            return new ServiceResponse(false, "Cannot update salary for terminated employee", "EMPLOYEE_INACTIVE");
        }

        // Validate salary change is within reasonable bounds (max 50% increase)
        BigDecimal maxAllowedSalary = employee.getSalary().multiply(new BigDecimal("1.50"));
        if (request.getNewSalary().compareTo(maxAllowedSalary) > 0) {
            return new ServiceResponse(false,
                    "Salary increase exceeds maximum allowed threshold (50%). Requires executive approval.",
                    "EXCEEDS_THRESHOLD");
        }

        BigDecimal oldSalary = employee.getSalary();
        employee.setSalary(request.getNewSalary());

        LOGGER.info("Salary updated for employee " + sanitizeLogInput(employeeId)
                + " from " + oldSalary + " to " + request.getNewSalary()
                + " approved by " + sanitizeLogInput(request.getApprovedBy()));

        return new ServiceResponse(true,
                "Salary updated successfully for employee " + employeeId);
    }

    @Override
    public ServiceResponse submitPerformanceReview(PerformanceReview review) {
        LOGGER.info("Processing performance review submission for employee: "
                + sanitizeLogInput(review != null ? review.getEmployeeId() : "null"));

        // Validate review
        if (review == null) {
            return new ServiceResponse(false, "Performance review data is required", "INVALID_REQUEST");
        }

        if (review.getEmployeeId() == null || review.getEmployeeId().trim().isEmpty()) {
            return new ServiceResponse(false, "Employee ID is required", "INVALID_REQUEST");
        }

        if (review.getReviewerId() == null || review.getReviewerId().trim().isEmpty()) {
            return new ServiceResponse(false, "Reviewer ID is required", "INVALID_REQUEST");
        }

        if (review.getRating() < 1 || review.getRating() > 5) {
            return new ServiceResponse(false, "Rating must be between 1 and 5", "INVALID_RATING");
        }

        if (review.getPeriod() == null || review.getPeriod().trim().isEmpty()) {
            return new ServiceResponse(false, "Review period is required", "INVALID_REQUEST");
        }

        // Sanitize comments to prevent injection
        if (review.getComments() != null) {
            review.setComments(sanitizeInput(review.getComments()));
        }

        String employeeId = review.getEmployeeId().trim();
        Employee employee = employeeStore.get(employeeId);

        if (employee == null) {
            return new ServiceResponse(false, "Employee not found", "EMPLOYEE_NOT_FOUND");
        }

        if (!employee.isActive()) {
            return new ServiceResponse(false, "Cannot submit review for terminated employee", "EMPLOYEE_INACTIVE");
        }

        // Check for duplicate review in same period
        boolean duplicateExists = employee.getPerformanceReviews().stream()
                .anyMatch(r -> r.getPeriod().equals(review.getPeriod())
                        && r.getReviewerId().equals(review.getReviewerId()));

        if (duplicateExists) {
            return new ServiceResponse(false,
                    "A review already exists for this period by the same reviewer",
                    "DUPLICATE_REVIEW");
        }

        // Generate review ID
        String reviewId = "REV-" + employeeId + "-" + UUID.randomUUID().toString().substring(0, 8);
        review.setReviewId(reviewId);

        if (review.getReviewDate() == null) {
            review.setReviewDate(LocalDate.now());
        }

        employee.getPerformanceReviews().add(review);

        LOGGER.info("Performance review " + reviewId + " submitted for employee " + sanitizeLogInput(employeeId));

        return new ServiceResponse(true,
                "Performance review submitted successfully. Review ID: " + reviewId);
    }

    @Override
    public PerformanceReview[] getPerformanceReviews(String employeeId) {
        LOGGER.info("Retrieving performance reviews for employee: " + sanitizeLogInput(employeeId));

        if (employeeId == null || employeeId.trim().isEmpty()) {
            return new PerformanceReview[0];
        }

        Employee employee = employeeStore.get(employeeId.trim());

        if (employee == null) {
            return new PerformanceReview[0];
        }

        List<PerformanceReview> reviews = employee.getPerformanceReviews();
        return reviews.toArray(new PerformanceReview[0]);
    }

    @Override
    public ServiceResponse terminateEmployee(TerminationRequest request) {
        LOGGER.info("Processing termination for employee: "
                + sanitizeLogInput(request != null ? request.getEmployeeId() : "null"));

        // Validate request
        if (request == null || request.getEmployeeId() == null || request.getEmployeeId().trim().isEmpty()) {
            return new ServiceResponse(false, "Employee ID is required", "INVALID_REQUEST");
        }

        if (request.getReason() == null || request.getReason().trim().isEmpty()) {
            return new ServiceResponse(false, "Termination reason is required", "INVALID_REQUEST");
        }

        if (request.getTerminationType() == null || request.getTerminationType().trim().isEmpty()) {
            return new ServiceResponse(false, "Termination type is required", "INVALID_REQUEST");
        }

        // Validate termination type
        Set<String> validTypes = Set.of("VOLUNTARY", "INVOLUNTARY", "RETIREMENT", "LAYOFF");
        if (!validTypes.contains(request.getTerminationType().toUpperCase())) {
            return new ServiceResponse(false,
                    "Invalid termination type. Must be one of: VOLUNTARY, INVOLUNTARY, RETIREMENT, LAYOFF",
                    "INVALID_TERMINATION_TYPE");
        }

        if (request.getProcessedBy() == null || request.getProcessedBy().trim().isEmpty()) {
            return new ServiceResponse(false, "Processor ID is required", "MISSING_PROCESSOR");
        }

        String employeeId = request.getEmployeeId().trim();
        Employee employee = employeeStore.get(employeeId);

        if (employee == null) {
            return new ServiceResponse(false, "Employee not found", "EMPLOYEE_NOT_FOUND");
        }

        if (!employee.isActive()) {
            return new ServiceResponse(false, "Employee is already terminated", "ALREADY_TERMINATED");
        }

        // Parse effective date
        LocalDate effectiveDate;
        if (request.getEffectiveDate() != null && !request.getEffectiveDate().trim().isEmpty()) {
            try {
                effectiveDate = LocalDate.parse(request.getEffectiveDate().trim(), DATE_FORMATTER);
            } catch (DateTimeParseException e) {
                return new ServiceResponse(false,
                        "Invalid effective date format. Use ISO format (YYYY-MM-DD)",
                        "INVALID_DATE");
            }
        } else {
            effectiveDate = LocalDate.now();
        }

        // Cannot terminate with a past date more than 30 days ago
        if (effectiveDate.isBefore(LocalDate.now().minusDays(30))) {
            return new ServiceResponse(false,
                    "Effective date cannot be more than 30 days in the past",
                    "INVALID_DATE");
        }

        employee.setActive(false);
        employee.setTerminationDate(effectiveDate);

        LOGGER.info("Employee " + sanitizeLogInput(employeeId) + " terminated. Type: "
                + request.getTerminationType() + ", Effective: " + effectiveDate
                + ", Processed by: " + sanitizeLogInput(request.getProcessedBy()));

        return new ServiceResponse(true,
                "Employee " + employeeId + " has been terminated effective " + effectiveDate);
    }

    @Override
    public Employee getEmployee(String employeeId) {
        LOGGER.info("Retrieving employee: " + sanitizeLogInput(employeeId));

        if (employeeId == null || employeeId.trim().isEmpty()) {
            return null;
        }

        return employeeStore.get(employeeId.trim());
    }

    /**
     * Sanitize input to prevent log injection attacks.
     */
    private String sanitizeLogInput(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n\\t]", "_");
    }

    /**
     * Sanitize general text input.
     */
    private String sanitizeInput(String input) {
        if (input == null) return null;
        // Remove potential script/markup content
        return input.replaceAll("[<>\"'&]", "");
    }
}

