// ============================================================
// ServicePublisher.java - Standalone endpoint publisher
// ============================================================

package com.hr.server;

import com.hr.service.EmployeeManagementServiceImpl;

import javax.xml.ws.Endpoint;
import java.util.logging.Logger;

/**
 * Standalone publisher for development/testing.
 * In production, deploy as WAR to application server with TLS configured.
 */
public class ServicePublisher {

    private static final Logger LOGGER = Logger.getLogger(ServicePublisher.class.getName());

    // Bind to localhost only - never expose directly to external network
    private static final String SERVICE_URL = "http://127.0.0.1:8443/services/employee";

    private Endpoint endpoint;

    public void start() {
        LOGGER.info("Starting Employee Management SOAP Service...");

        EmployeeManagementServiceImpl serviceImpl = new EmployeeManagementServiceImpl();
        endpoint = Endpoint.create(serviceImpl);

        // Publish endpoint - in production, use HTTPS with proper TLS configuration
        endpoint.publish(SERVICE_URL);

        LOGGER.info("Employee Management Service published at: " + SERVICE_URL);
        LOGGER.info("WSDL available at: " + SERVICE_URL + "?wsdl");
        LOGGER.info("NOTE: In production, deploy behind TLS-terminating reverse proxy");
        LOGGER.info("NOTE: WSDL access should be restricted to internal networks only");
    }

    public void stop() {
        if (endpoint != null && endpoint.isPublished()) {
            endpoint.stop();
            LOGGER.info("Employee Management Service stopped");
        }
    }

    public static void main(String[] args) {
        ServicePublisher publisher = new ServicePublisher();
        publisher.start();

        // Add shutdown hook for graceful shutdown
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            LOGGER.info("Shutting down service...");
            publisher.stop();
        }));

        LOGGER.info("Service is running. Press Ctrl+C to stop.");
    }
}

